#' Check for required external dependencies
#'
#' Performs pre-flight checks to ensure required external tools are available.
#'
#' @param tools Character vector of tools to check. Currently supports "quarto"
#'   and "pandoc".
#' @param quiet Logical. Whether to suppress informational messages. Defaults to FALSE.
#'
#' @return Logical indicating whether all checks passed. Also sets attributes
#'   with detailed check results.
#'
#' @examples
#' \dontrun{
#' # Check for Quarto
#' sv_preflight_check("quarto")
#'
#' # Check for multiple tools
#' sv_preflight_check(c("quarto", "pandoc"))
#' }
#'
#' @export
sv_preflight_check <- function(tools, quiet = FALSE) {
  results <- list()
  all_passed <- TRUE

  for (tool in tools) {
    result <- switch(tool,
      quarto = check_quarto(quiet),
      pandoc = check_pandoc(quiet),
      {
        warning("Unknown tool: ", tool)
        list(available = FALSE, version = NA, path = NA)
      }
    )

    results[[tool]] <- result
    if (!result$available) {
      all_passed <- FALSE
    }
  }

  # Return logical with results as attributes
  structure(all_passed, results = results)
}

#' Check for Quarto installation
#'
#' @param quiet Logical. Suppress messages.
#' @return List with available, version, and path
#' @noRd
check_quarto <- function(quiet = FALSE) {
  # Try to find quarto
  quarto_path <- Sys.which("quarto")

  if (quarto_path == "") {
    if (!quiet) {
      message("Quarto not found in PATH.")
      message("Please install Quarto from: https://quarto.org/docs/get-started/")
    }
    return(list(available = FALSE, version = NA, path = NA))
  }

  # Get version
  version <- tryCatch({
    result <- system2("quarto", "--version", stdout = TRUE, stderr = FALSE)
    trimws(result[1])
  }, error = function(e) NA)

  if (!quiet) {
    message("✓ Quarto found: ", quarto_path)
    if (!is.na(version)) {
      message("  Version: ", version)
    }
  }

  list(available = TRUE, version = version, path = quarto_path)
}

#' Check for Pandoc installation
#'
#' @param quiet Logical. Suppress messages.
#' @return List with available, version, and path
#' @noRd
check_pandoc <- function(quiet = FALSE) {
  # First check if rmarkdown's pandoc is available
  if (requireNamespace("rmarkdown", quietly = TRUE)) {
    pandoc_dir <- rmarkdown::find_pandoc()
    if (!is.null(pandoc_dir$dir) && pandoc_dir$dir != "") {
      if (!quiet) {
        message("✓ Pandoc found via rmarkdown: ", pandoc_dir$dir)
        message("  Version: ", pandoc_dir$version)
      }
      return(list(
        available = TRUE, 
        version = as.character(pandoc_dir$version),
        path = file.path(pandoc_dir$dir, "pandoc")
      ))
    }
  }

  # Fall back to system pandoc
  pandoc_path <- Sys.which("pandoc")

  if (pandoc_path == "") {
    if (!quiet) {
      message("Pandoc not found.")
      message("Install via:")
      message("  - R: install.packages('rmarkdown')")
      message("  - System: https://pandoc.org/installing.html")
    }
    return(list(available = FALSE, version = NA, path = NA))
  }

  # Get version
  version <- tryCatch({
    result <- system2("pandoc", "--version", stdout = TRUE, stderr = FALSE)
    # Extract version from first line
    version_line <- result[1]
    version_match <- regmatches(version_line, regexpr("[0-9]+\\.[0-9]+[\\.[0-9]+]*", version_line))
    if (length(version_match) > 0) version_match[1] else NA
  }, error = function(e) NA)

  if (!quiet) {
    message("✓ Pandoc found: ", pandoc_path)
    if (!is.na(version)) {
      message("  Version: ", version)
    }
  }

  list(available = TRUE, version = version, path = pandoc_path)
}

#' Check and suggest missing dependencies
#'
#' @param tools Character vector of missing tools
#' @noRd
suggest_missing_deps <- function(tools) {
  suggestions <- list(
    quarto = c(
      "Quarto is required to generate reports.",
      "Install from: https://quarto.org/docs/get-started/",
      "Or use your package manager:",
      "  - macOS: brew install quarto",
      "  - Ubuntu/Debian: See website for .deb package",
      "  - Windows: Download installer from website"
    ),
    pandoc = c(
      "Pandoc is required for document conversion.",
      "Install via R: install.packages('rmarkdown')",
      "Or from: https://pandoc.org/installing.html"
    )
  )

  for (tool in tools) {
    if (tool %in% names(suggestions)) {
      message("\n", paste(suggestions[[tool]], collapse = "\n"))
    }
  }
}

